132	int search_ref_dir(struct ref_dir *dir, const char *refname, size_t len)
133	{
134		struct ref_entry **r;
135		struct string_slice key;
136	
137		if (refname == NULL || !dir->nr)
138			return -1;
139	
140		sort_ref_dir(dir);
141		key.len = len;
142		key.str = refname;
143		r = bsearch(&key, dir->entries, dir->nr, sizeof(*dir->entries),
144			    ref_entry_cmp_sslice);
145	
146		if (!r)
147			return -1;
148	
149		return r - dir->entries;
150	}
151	
152	/*
153	 * Search for a directory entry directly within dir (without
154	 * recursing).  Sort dir if necessary.  subdirname must be a directory
155	 * name (i.e., end in '/'). Returns NULL if the desired
156	 * directory cannot be found.  dir must already be complete.
157	 */
158	static struct ref_dir *search_for_subdir(struct ref_dir *dir,
159						 const char *subdirname, size_t len)
160	{
161		int entry_index = search_ref_dir(dir, subdirname, len);
162		struct ref_entry *entry;
163	
164		if (entry_index == -1)
165			return NULL;
166	
167		entry = dir->entries[entry_index];
168		return get_ref_dir(entry);
169	}
170	
171	/*
172	 * If refname is a reference name, find the ref_dir within the dir
173	 * tree that should hold refname. If refname is a directory name
174	 * (i.e., it ends in '/'), then return that ref_dir itself. dir must
175	 * represent the top-level directory and must already be complete.
176	 * Sort ref_dirs and recurse into subdirectories as necessary. Will
177	 * return NULL if the desired directory cannot be found.
178	 */
179	static struct ref_dir *find_containing_dir(struct ref_dir *dir,
180						   const char *refname)
181	{
182		const char *slash;
183		for (slash = strchr(refname, '/'); slash; slash = strchr(slash + 1, '/')) {
184			size_t dirnamelen = slash - refname + 1;
185			struct ref_dir *subdir;
186			subdir = search_for_subdir(dir, refname, dirnamelen);
187			if (!subdir) {
188				dir = NULL;
189				break;
190			}
191			dir = subdir;
192		}
193	
194		return dir;
195	}
196	
197	/*
198	 * Emit a warning and return true iff ref1 and ref2 have the same name
199	 * and the same oid. Die if they have the same name but different
200	 * oids.
201	 */
202	static int is_dup_ref(const struct ref_entry *ref1, const struct ref_entry *ref2)
203	{
204		if (strcmp(ref1->name, ref2->name))
205			return 0;
206	
207		/* Duplicate name; make sure that they don't conflict: */
208	
209		if ((ref1->flag & REF_DIR) || (ref2->flag & REF_DIR))
210			/* This is impossible by construction */
211			die("Reference directory conflict: %s", ref1->name);
212	
213		if (!oideq(&ref1->u.value.oid, &ref2->u.value.oid))
214			die("Duplicated ref, and SHA1s don't match: %s", ref1->name);
215	
216		warning("Duplicated ref: %s", ref1->name);
217		return 1;
218	}
219	
220	/*
221	 * Sort the entries in dir non-recursively (if they are not already
222	 * sorted) and remove any duplicate entries.
223	 */
224	static void sort_ref_dir(struct ref_dir *dir)
225	{
226		int i, j;
227		struct ref_entry *last = NULL;
228	
229		/*
230		 * This check also prevents passing a zero-length array to qsort(),
231		 * which is a problem on some platforms.
232		 */
233		if (dir->sorted == dir->nr)
234			return;
235	
236		QSORT(dir->entries, dir->nr, ref_entry_cmp);
237	
238		/* Remove any duplicates: */
239		for (i = 0, j = 0; j < dir->nr; j++) {
240			struct ref_entry *entry = dir->entries[j];
241			if (last && is_dup_ref(last, entry))
242				free_ref_entry(entry);
243			else
244				last = dir->entries[i++] = entry;
245		}
246		dir->sorted = dir->nr = i;
247	}
248	
249	enum prefix_state {
250		/* All refs within the directory would match prefix: */
251		PREFIX_CONTAINS_DIR,
252	
253		/* Some, but not all, refs within the directory might match prefix: */
254		PREFIX_WITHIN_DIR,
255	
256		/* No refs within the directory could possibly match prefix: */
257		PREFIX_EXCLUDES_DIR
258	};
259	
260	/*
261	 * Return a `prefix_state` constant describing the relationship
262	 * between the directory with the specified `dirname` and `prefix`.
263	 */
264	static enum prefix_state overlaps_prefix(const char *dirname,
265						 const char *prefix)
266	{
267		while (*prefix && *dirname == *prefix) {
268			dirname++;
269			prefix++;
270		}
271		if (!*prefix)
272			return PREFIX_CONTAINS_DIR;
273		else if (!*dirname)
274			return PREFIX_WITHIN_DIR;
275		else
276			return PREFIX_EXCLUDES_DIR;
277	}
278	
279	/*
280	 * Load all of the refs from `dir` (recursively) that could possibly
281	 * contain references matching `prefix` into our in-memory cache. If
282	 * `prefix` is NULL, prime unconditionally.
283	 */
284	static void prime_ref_dir(struct ref_dir *dir, const char *prefix)
285	{
286		/*
287		 * The hard work of loading loose refs is done by get_ref_dir(), so we
288		 * just need to recurse through all of the sub-directories. We do not
289		 * even need to care about sorting, as traversal order does not matter
290		 * to us.
291		 */
292		int i;
293		for (i = 0; i < dir->nr; i++) {
294			struct ref_entry *entry = dir->entries[i];
295			if (!(entry->flag & REF_DIR)) {
296				/* Not a directory; no need to recurse. */
297			} else if (!prefix) {
298				/* Recurse in any case: */
299				prime_ref_dir(get_ref_dir(entry), NULL);
300			} else {
301				switch (overlaps_prefix(entry->name, prefix)) {
302				case PREFIX_CONTAINS_DIR:
303					/*
304					 * Recurse, and from here down we
305					 * don't have to check the prefix
306					 * anymore:
307					 */
308					prime_ref_dir(get_ref_dir(entry), NULL);
309					break;
310				case PREFIX_WITHIN_DIR:
311					prime_ref_dir(get_ref_dir(entry), prefix);
312					break;
313				case PREFIX_EXCLUDES_DIR:
314					/* No need to prime this directory. */
315					break;
316				}
317			}
318		}
319	}
320	
321	/*
322	 * A level in the reference hierarchy that is currently being iterated
323	 * through.
324	 */
325	struct cache_ref_iterator_level {
326		/*
327		 * The ref_dir being iterated over at this level. The ref_dir
328		 * is sorted before being stored here.
329		 */
330		struct ref_dir *dir;
331	
332		enum prefix_state prefix_state;
333	
334		/*
335		 * The index of the current entry within dir (which might
336		 * itself be a directory). If index == -1, then the iteration
337		 * hasn't yet begun. If index == dir->nr, then the iteration
338		 * through this level is over.
339		 */
340		int index;
341	};
342	
343	/*
344	 * Represent an iteration through a ref_dir in the memory cache. The
345	 * iteration recurses through subdirectories.
346	 */
347	struct cache_ref_iterator {
348		struct ref_iterator base;
349	
350		/*
351		 * The number of levels currently on the stack.
352		 */
353		size_t levels_nr;
354	
355		/* The number of levels that have been allocated on the stack */
356		size_t levels_alloc;
357	
358		/*
359		 * Only include references with this prefix in the iteration.
360		 * The prefix is matched textually, without regard for path
361		 * component boundaries.
362		 */
363		char *prefix;
364	
365		/*
366		 * A stack of levels. levels[0] is the uppermost level that is
367		 * being iterated over in this iteration. (This is not
368		 * necessary the top level in the references hierarchy. If we
369		 * are iterating through a subtree, then levels[0] will hold
370		 * the ref_dir for that subtree, and subsequent levels will go
371		 * on from there.)
372		 */
373		struct cache_ref_iterator_level *levels;
374	
375		struct repository *repo;
376		struct ref_cache *cache;
377	
378		int prime_dir;
379	};
380	
381	static int cache_ref_iterator_advance(struct ref_iterator *ref_iterator)
382	{
383		struct cache_ref_iterator *iter =
384			(struct cache_ref_iterator *)ref_iterator;
385	
386		if (!iter->levels_nr)
387			return ITER_DONE;
388	
389		while (1) {
390			struct cache_ref_iterator_level *level =
391				&iter->levels[iter->levels_nr - 1];
392			struct ref_dir *dir = level->dir;
393			struct ref_entry *entry;
394			enum prefix_state entry_prefix_state;
395	
396			if (level->index == -1)
397				sort_ref_dir(dir);
398	
399			if (++level->index == level->dir->nr) {
400				/* This level is exhausted; pop up a level */
401				if (--iter->levels_nr == 0)
402					return ITER_DONE;
403	
404				continue;
405			}
406	
407			entry = dir->entries[level->index];
408	
409			if (level->prefix_state == PREFIX_WITHIN_DIR) {
410				entry_prefix_state = overlaps_prefix(entry->name, iter->prefix);
411				if (entry_prefix_state == PREFIX_EXCLUDES_DIR ||
412				    (entry_prefix_state == PREFIX_WITHIN_DIR && !(entry->flag & REF_DIR)))
413					continue;
414			} else {
415				entry_prefix_state = level->prefix_state;
416			}
417	
418			if (entry->flag & REF_DIR) {
419				/* push down a level */
420				ALLOC_GROW(iter->levels, iter->levels_nr + 1,
421					   iter->levels_alloc);
422	
423				level = &iter->levels[iter->levels_nr++];
424				level->dir = get_ref_dir(entry);
425				level->prefix_state = entry_prefix_state;
426				level->index = -1;
427			} else {
428				memset(&iter->base.ref, 0, sizeof(iter->base.ref));
429				iter->base.ref.name = entry->name;
430				iter->base.ref.target = entry->u.value.referent;
431				iter->base.ref.oid = &entry->u.value.oid;
432				iter->base.ref.flags = entry->flag;
433				return ITER_OK;
434			}
435		}
436	}
437	
438	static int cache_ref_iterator_set_prefix(struct cache_ref_iterator *iter,
439						 const char *prefix)
440	{
441		struct cache_ref_iterator_level *level;
442		struct ref_dir *dir;
443	
444		dir = get_ref_dir(iter->cache->root);
445		if (prefix && *prefix)
446			dir = find_containing_dir(dir, prefix);
447		if (!dir) {
448			iter->levels_nr = 0;
449			return 0;
450		}
451	
452		if (iter->prime_dir)
453			prime_ref_dir(dir, prefix);
454		iter->levels_nr = 1;
455		level = &iter->levels[0];
456		level->index = -1;
457		level->dir = dir;
458	
459		if (prefix && *prefix) {
460			free(iter->prefix);
461			iter->prefix = xstrdup(prefix);
462			level->prefix_state = PREFIX_WITHIN_DIR;
463		} else {
464			FREE_AND_NULL(iter->prefix);
465			level->prefix_state = PREFIX_CONTAINS_DIR;
466		}
467	
468		return 0;
469	}
470	
471	static int cache_ref_iterator_seek(struct ref_iterator *ref_iterator,
472					   const char *refname, unsigned int flags)
473	{
474		struct cache_ref_iterator *iter =
475			(struct cache_ref_iterator *)ref_iterator;
476	
477		if (flags & REF_ITERATOR_SEEK_SET_PREFIX) {
478			return cache_ref_iterator_set_prefix(iter, refname);
479		} else if (refname && *refname) {
480			struct cache_ref_iterator_level *level;
481			const char *slash = refname;
482			struct ref_dir *dir;
483	
484			dir = get_ref_dir(iter->cache->root);
485	
486			if (iter->prime_dir)
487				prime_ref_dir(dir, refname);
488	
489			iter->levels_nr = 1;
490			level = &iter->levels[0];
491			level->index = -1;
492			level->dir = dir;
493	
494			/* Unset any previously set prefix */
495			FREE_AND_NULL(iter->prefix);
496	
497			/*
498			 * Breakdown the provided seek path and assign the correct
499			 * indexing to each level as needed.
500			 */
501			do {
502				int idx;
503				size_t len;
504				int cmp = 0;
505	
506				sort_ref_dir(dir);
507	
508				slash = strchr(slash, '/');
509				len = slash ? (size_t)(slash - refname) : strlen(refname);
510	
511				for (idx = 0; idx < dir->nr; idx++) {
512					cmp = strncmp(refname, dir->entries[idx]->name, len);
513					if (cmp <= 0)
514						break;
515				}
516				/* don't overflow the index */
517				idx = idx >= dir->nr ? dir->nr - 1 : idx;
518	
519				if (slash)
520					slash = slash + 1;
521	
522				level->index = idx;
523				if (dir->entries[idx]->flag & REF_DIR) {
524					/* push down a level */
525					dir = get_ref_dir(dir->entries[idx]);
526	
527					ALLOC_GROW(iter->levels, iter->levels_nr + 1,
528						   iter->levels_alloc);
529					level = &iter->levels[iter->levels_nr++];
530					level->dir = dir;
531					level->index = -1;
532					level->prefix_state = PREFIX_CONTAINS_DIR;
533				} else {
534					/* reduce the index so the leaf node is iterated over */
535					if (cmp <= 0 && !slash)
536						level->index = idx - 1;
537					/*
538					 * while the seek path may not be exhausted, our
539					 * match is exhausted at a leaf node.
540					 */
541					break;
542				}
543			} while (slash && dir->nr);
544		}
545	
546		return 0;
547	}
548	
549	static void cache_ref_iterator_release(struct ref_iterator *ref_iterator)
550	{
551		struct cache_ref_iterator *iter =
552			(struct cache_ref_iterator *)ref_iterator;
553		free(iter->prefix);
554		free(iter->levels);
555	}
556	
557	static struct ref_iterator_vtable cache_ref_iterator_vtable = {
558		.advance = cache_ref_iterator_advance,
559		.seek = cache_ref_iterator_seek,
560		.release = cache_ref_iterator_release,
561	};
562	
563	struct ref_iterator *cache_ref_iterator_begin(struct ref_cache *cache,
564						      const char *prefix,
565						      struct repository *repo,
566						      int prime_dir)
567	{
568		struct cache_ref_iterator *iter;
569		struct ref_iterator *ref_iterator;
570	
571		CALLOC_ARRAY(iter, 1);
572		ref_iterator = &iter->base;
573		base_ref_iterator_init(ref_iterator, &cache_ref_iterator_vtable);
574		ALLOC_GROW(iter->levels, 10, iter->levels_alloc);
575	
576		iter->repo = repo;
577		iter->cache = cache;
578		iter->prime_dir = prime_dir;
579	
580		if (cache_ref_iterator_seek(&iter->base, prefix,
581					    REF_ITERATOR_SEEK_SET_PREFIX) < 0) {
582			ref_iterator_free(&iter->base);
583			return NULL;
584		}
585	
586		return ref_iterator;
587	}
